card_mod.style:
ha-card {
  height: 100%;
  box-sizing: border-box;
  border-radius: 28px;
  background: rgba(255,255,255,0.045);
  border: 1px solid rgba(255,255,255,0.07);
  padding: 22px;
  --icon-size: 58px;
  --card-primary-font-size: 26px;
  --card-primary-font-weight: 600;
  --card-secondary-font-size: 16px;
  --primary-text-color: #f2f0ec;
  --secondary-text-color: rgba(242,240,236,0.55);
  --rgb-state-light: 255, 179, 84;
  --rgb-state-switch: 255, 179, 84;
  --rgb-disabled: 120, 120, 120;
}

